ushort lastValue = 0;
for (int i = 0; i < 5; i++)
{
    ushort current = Plc.ReadHoldingRegister(100);
    if (current == lastValue)
        Print($"[{i}] 缓存命中 → {current}");
    else
    {
        Print($"[{i}] 新数据: {current}");
        lastValue = current;
    }
}
